const STYLE = `Ты пишешь посты для Telegram-канала НейроСвета от лица Светланы Голубевой.
Светлана — эксперт по ИИ, помогает предпринимателям внедрять ИИ в бизнес.
Голос: тёплый, уверенный, как подруга-эксперт. Без воды и канцелярита.
Короткие абзацы, умеренно эмодзи, конкретные цифры.
НЕ используй: революционный, прорыв, невероятный, уникальный.`;

const COURSE_NAME = 'мой курс по ИИ';
const COURSE_URL = 'ссылка в шапке профиля';

return $input.all().map(item => ({
  json: {
    ...item.json,
    prompts: {
      format1: `${STYLE}

Напиши Telegram-пост «Горячая новость» (600–1000 символов).
Начни с неожиданного факта, не копируй заголовок.
Объясни что это значит для предпринимателей.
Закончи вопросом к аудитории.

Новость: ${item.json.title}
Содержание: ${item.json.summary_ru}`,
      format2: `${STYLE}

Напиши Telegram-пост «Инструмент/Лайфхак» (700–1200 символов).
Начни с конкретного результата в цифрах.
Дай 3–5 шагов как использовать.

Новость: ${item.json.title}
Содержание: ${item.json.summary_ru}`,
      format3: `${STYLE}

Напиши Telegram-пост «История + продажа курса» (800–1500 символов).
История от первого лица: точка А → поворот → результат.
ОБЯЗАТЕЛЬНО в конце CTA: упомяни «${COURSE_NAME}» и «${COURSE_URL}».

Новость: ${item.json.title}
Содержание: ${item.json.summary_ru}`
    }
  }
}));

const f1 = $('Groq: Формат 1').first()?.json?.choices?.[0]?.message?.content || '(не удалось создать)';
const f2 = $('Groq: Формат 2').first()?.json?.choices?.[0]?.message?.content || '(не удалось создать)';
const f3 = $('Groq: Формат 3').first()?.json?.choices?.[0]?.message?.content || '(не удалось создать)';
const article = $('Собрать промпты').first().json;

return [{ json: { article: { title: article.title, url: article.url }, posts: { format1: f1, format2: f2, format3: f3 } } }];
